import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import api from '../utils/api';
import ProductCard from '../components/ProductCard';
import './HomePage.css';

const TICKER_ITEMS = [
  'Iced Out Chains','Diamond Pendants','Custom Grillz','Hip Hop Rings',
  'Celebrity Jeweler','Surat · Gujarat','Worldwide Shipping','Custom Design','Since 2018'
];

export default function HomePage() {
  const [featured, setFeatured] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const loadProducts = async () => {
      try {
        // First try featured products
        const res = await api.get('/products?featured=true&limit=4');
        if (res.data.products && res.data.products.length > 0) {
          setFeatured(res.data.products);
        } else {
          // If no featured products, just load the latest 4
          const fallback = await api.get('/products?sort=newest&limit=4');
          setFeatured(fallback.data.products || []);
        }
      } catch {
